#!/usr/bin/env bash
# PostToolUse hook — lint TypeScript/TSX files after Edit/Write
# Advisory only — never blocks. Fails open if eslint is not available.
# Generated by /setup with repo paths filled in. Copy to .claude/hooks/lint-ts.sh.

set +e

input=$(cat)
file=$(printf '%s' "$input" | python3 -c "import sys, json; d=json.load(sys.stdin); print(d.get('tool_input', {}).get('file_path') or d.get('tool_response', {}).get('filePath') or '')" 2>/dev/null || echo "")

[ -z "$file" ] && exit 0

case "$file" in
  *.ts|*.tsx) ;;
  *) exit 0 ;;
esac

# --- CONFIGURE: add your repo paths here ---
# /setup replaces this section with actual paths.
repo=""
# Example:
# case "$file" in
#   /path/to/your/frontend/*) repo=/path/to/your/frontend ;;
#   /path/to/your/admin/*) repo=/path/to/your/admin ;;
# esac
# --- END CONFIGURE ---

[ -z "$repo" ] && exit 0

# Locate eslint: repo-local first, then PATH
eslint_bin=""
if [ -x "$repo/node_modules/.bin/eslint" ]; then
  eslint_bin="$repo/node_modules/.bin/eslint"
elif command -v eslint >/dev/null 2>&1; then
  eslint_bin="eslint"
else
  exit 0
fi

cd "$repo" || exit 0
output=$("$eslint_bin" --max-warnings 0 -- "$file" 2>&1)
status=$?
if [ $status -ne 0 ]; then
  echo "[lint-ts] $file" >&2
  echo "$output" >&2
fi

exit 0
